def process_log(log_path, output_path):
    """Process a log file and write results - but leaks file handles!"""
    f = open(log_path, 'r')
    lines = f.readlines()
    f.close()

    out = open(output_path, 'w')
    for line in lines:
        if 'ERROR' in line:
            out.write(line)
    out.close()

    return len(lines)
